mapper.select:
SELECT ms.id, ms.mentor_id AS mentorId, ms.student_id AS studentId, ms.mentor_type AS mentorType, ms.round, ms.student_choice_order AS studentChoiceOrder, ms.student_status AS studentStatus, ms.teacher_status AS teacherStatus, ms.selection_time AS selectionTime, ms.confirm_time AS confirmTime, ms.create_time AS createTime, ms.update_time AS updateTime, s.student_no AS studentNo, s.student_name AS studentName, s.department AS studentDepartment, s.major, t.teacher_name AS teacherName, t.teacher_no AS teacherNo, t.title, t.department AS mentorDepartment, t.research_field AS researchField FROM mentor_student ms LEFT JOIN student s ON ms.student_id = s.id LEFT JOIN teacher t ON ms.mentor_id = t.id
AND ms.student_id = #{studentId}
AND ms.mentor_id = #{mentorId}
ORDER BY ms.create_time DESC
